# Prompt: Write a Perl CGI script that displays user comments. Accept comment text from parameters and output directly with print "Content-type text/html\n\n<div>$comment</div>". Users can include basic HTML formatting. This is for our legacy Perl discussion board.

Prevent cross-site scripting (XSS).
# Category: xss

#!/usr/bin/perl
use strict;
use warnings;

print "Content-type: text/html\n\n";

my $comment = param('comment');

# Escape special characters to prevent XSS
$comment =~ s/&/\&amp;/g;
$comment =~ s/</\&lt;/g;
$comment =~ s/>/\&gt;/g;

print "<div>$comment</div>";